import{_ as a,o as l,c as i,ae as o}from"./chunks/framework.Czhw_PXq.js";const p=JSON.parse('{"title":"语言支持发布交接（2026-04-09）","description":"","frontmatter":{},"headers":[],"relativePath":"superpowers/baselines/2026-04-09-language-support/release-handoff.zh-CN.md","filePath":"superpowers/baselines/2026-04-09-language-support/release-handoff.zh-CN.md"}'),d={name:"superpowers/baselines/2026-04-09-language-support/release-handoff.zh-CN.md"};function t(c,e,r,s,n,u){return l(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="语言支持发布交接-2026-04-09" tabindex="-1">语言支持发布交接（2026-04-09） <a class="header-anchor" href="#语言支持发布交接-2026-04-09" aria-label="Permalink to &quot;语言支持发布交接（2026-04-09）&quot;">​</a></h1><h2 id="范围" tabindex="-1">范围 <a class="header-anchor" href="#范围" aria-label="Permalink to &quot;范围&quot;">​</a></h2><p>本交接覆盖第一性原理语言支持改造：</p><ul><li>语言域模型（<code>uiLocale</code> + 任务语言策略）。</li><li>带 locale fallback 的 UI i18n 基础设施。</li><li>设置页、侧边栏与错误提示等运行时字符串迁移。</li><li>prompt 与处理流程中的统一语言决策路径。</li><li>locale-aware 时间格式与 RTL-safe 样式保护。</li><li>脚本化 baseline/compare 回归工作流。</li></ul><h2 id="前后对比摘要" tabindex="-1">前后对比摘要 <a class="header-anchor" href="#前后对比摘要" aria-label="Permalink to &quot;前后对比摘要&quot;">​</a></h2><ul><li>基线构建此前不稳定，原因是 <code>ref/**</code> 被纳入 TypeScript 编译范围，触发 <code>TS6059</code>。</li><li>当前构建范围已排除 <code>ref/**</code>；最终 <code>npm run build</code> 为 PASS。</li><li>定向行为矩阵在迁移前后均保持 PASS。</li><li>集成后的完整 <code>npm test -- --runInBand</code> 为 PASS。</li><li><code>git diff --check</code> 未发现格式问题。</li></ul><h2 id="最终验证证据" tabindex="-1">最终验证证据 <a class="header-anchor" href="#最终验证证据" aria-label="Permalink to &quot;最终验证证据&quot;">​</a></h2><ul><li>Build：<code>task9-build-after-docs.txt</code></li><li>定向矩阵：<code>task9-targeted-matrix.txt</code></li><li>完整测试：<code>task9-full-runInBand.txt</code></li><li>回归脚本：<code>task9-regression-baseline.txt</code>、<code>task9-regression-compare.txt</code></li><li>Patch 质量：<code>task9-git-diff-check.txt</code></li><li>Obsidian 命令检查：<code>task9-obsidian-help.txt</code>、<code>task9-obsidian-cli-help.txt</code></li></ul><p>上述文件均位于：</p><ul><li><code>docs/superpowers/baselines/2026-04-09-language-support/</code></li></ul><h2 id="剩余风险" tabindex="-1">剩余风险 <a class="header-anchor" href="#剩余风险" aria-label="Permalink to &quot;剩余风险&quot;">​</a></h2><ul><li>环境依赖：当前执行环境缺少 <code>obsidian-cli</code>（<code>command not found</code>），因此 CLI 验证仍是不完整的。</li><li>宿主依赖：<code>obsidian help</code> 的行为可能在 headless 或桌面受限环境中发生变化。</li></ul><h2 id="发布就绪说明" tabindex="-1">发布就绪说明 <a class="header-anchor" href="#发布就绪说明" aria-label="Permalink to &quot;发布就绪说明&quot;">​</a></h2><ul><li>代码与文档已经针对语言架构和回归流程保持同步。</li><li><code>README.md</code> 与 <code>README_zh.md</code> 已同时记录维护者发布约束： <ul><li>独立可读的中英双语 release 文案；</li><li>release 必需资产必须包含 <code>README.md</code>。</li></ul></li><li>推荐发布门禁保持为： <ul><li><code>npm run build</code></li><li><code>npm test -- --runInBand</code></li><li><code>npm run regression:language-compare</code></li></ul></li></ul>',14)])])}const f=a(d,[["render",t]]);export{p as __pageData,f as default};
